function formattedSince(ts)
{
    var diff = since(ts)
    if (diff < 60) {
        return `${diff}s`
    }

    diff = Math.floor(diff / 60)
    if (diff < 60) {
        return `${diff}m`
    }

    diff = Math.floor(diff / 60)
    if (diff < 24) {
        return `${diff}h`
    }

    diff = Math.floor(diff / 24)
    return `${diff}d`
}


function since(ts)
{
    return Math.floor((Date.now() - ts) / 1000);
}
